reactquery.content:
TanStack Query 学习笔记
概述
TanStack Query 是一个强大的数据同步库，用于 React 应用的状态管理和数据获取。
注：本文档基于 TanStack Query 最新版本整理，具体使用请参考 tanstack.com/query/latest
&quot;@tanstack/react-query&quot;: &quot;^5.91.0&quot;,
&quot;@tanstack/react-query-devtools&quot;: &quot;^5.91.3&quot;,
安装
基础安装
npm i @tanstack/react-query
ESLint 插件（可选）
npm i -D @tanstack/eslint-plugin-query
开发工具（可选）
npm i @tanstack/react-query-devtools
基础配置
设置 React Query
import { QueryClient, QueryClientProvider } from &quot;@tanstack/react-query&quot;;

const queryClient = new QueryClient();

function App() {
	return (
		&lt;QueryClientProvider client={queryClient}&gt;
			{/* 你的应用组件 */}
		&lt;/QueryClientProvider&gt;
	);
}
开发工具集成
import { ReactQueryDevtools } from &quot;@tanstack/react-query-devtools&quot;;

function App() {
	return (
		&lt;QueryClientProvider client={queryClient}&gt;
			{/* 你的应用其他部分 */}
			&lt;ReactQueryDevtools initialIsOpen={false} /&gt;
		&lt;/QueryClientProvider&gt;
	);
}
useQuery Hook
基本用法
useQuery 是获取数据的主要钩子函数。
参数：

key：唯一标识符，用于缓存和查询
queryFn：用于获取数据的函数
options：配置选项

代码示例
import { useQuery } from &#039;@tanstack/react-query&#039;

// 通用的数据获取函数
function fetcher&lt;T&gt;(url: string): Promise&lt;T&gt; {
  return fetch(url).then((res) =&gt; res.json())
}

// 使用示例
function Page() {
  const query = useQuery([&#039;todos&#039;], fetcher)
  const { status, fetchStatus, isLoading, isFetching, data, error } = query;
  // 首次加载
  if (isLoading &amp;&amp; isFetching) return &lt;span&gt;Loading...&lt;/span&gt;
  // 有缓存的后台刷新
  if (status === &#039;success&#039; &amp;&amp; fetchStatus === &#039;fetching&#039;) return &lt;span&gt;Refreshing...&lt;/span&gt;
  // 失败
  if (status === &#039;error&#039; &amp;&amp; fetchStatus === &#039;idle&#039;) return &lt;span&gt;Error: {error.message}&lt;/span&gt;
  // 网络暂停
  if (fetchStatus === &#039;paused&#039;) return &lt;span&gt;Network paused. Click to resume.&lt;/span&gt;

  return (
    &lt;ul&gt;
      {data.map((todo) =&gt; (
        &lt;li key={todo.id}&gt;{todo.title}&lt;/li&gt;
      ))}
    &lt;/ul&gt;
  )
}
// { id: 1, name: &quot;张三&quot;, email: &quot;zhang@example.com&quot;, avatar: &quot;...&quot;, ... }
const { data: userInfo } = useQuery({
	queryKey: [&quot;user&quot;, 1],
	queryFn: fetchUser,
	select: (user) =&gt; ({
		// 重组数据
		name: user.name,
		email: user.email,
		avatar: user.avatar,
	}),
});
返回对象属性


















































属性名类型描述dataT查询返回的数据errorError查询过程中的错误对象isLoadingboolean是否正在加载（第一次加载）isFetchingboolean是否正在获取数据（包括后台刷新）isErrorboolean是否有错误refetchfunction手动重新获取数据的函数statusstring描述数据本身的状态（‘pending’、‘error’、‘success’）fetchStatusstring描述获取过程的状态（‘idle’、‘fetching’、‘paused’）
查询键（Query Keys）
查询键用于唯一标识查询，并用于缓存管理。
useQuery([&quot;todos&quot;], fetcher); // 旧版本（v4 及之前）

useQuery({
	// 新版本（v5 及之后）
	queryKey: [&quot;todo&quot;, 5, { preview: true }],
	queryFn: fetchTodo,
});

查询函数参数（QueryFunctionContext）

queryKey：获取查询参数
client：查询客户端实例
signal：请求取消（必须使用，避免内存泄漏）
pageParam：无限查询的页码
meta：传递额外配置

queryOptions | TypeScript辅助工具
在多个地方共享查询键和查询函数的同时，又能确保它们保持相互关联，最好的方法就是使用查询选项辅助工具
import { queryOptions } from &quot;@tanstack/react-query&quot;;

function groupOptions(id: number) {
	return queryOptions({
		queryKey: [&quot;groups&quot;, id],
		queryFn: () =&gt; fetchGroups(id),
		staleTime: 5 * 1000,
	});
}
useQuery(groupOptions(1));
useQueries({
	queries: [groupOptions(1), groupOptions(2)],
});
useQueries Hook | 并行查询
useQueries 是用于同时管理多个查询的钩子函数。
import { useQueries } from &quot;@tanstack/react-query&quot;;

const results = useQueries({
	queries: [
		{ queryKey: [&quot;user&quot;, 1], queryFn: fetchUser },
		{ queryKey: [&quot;posts&quot;], queryFn: fetchPosts },
		{ queryKey: [&quot;todos&quot;], queryFn: fetchTodos },
	],
});
// 或
const results = useQueries({
	queries: users.map((user) =&gt; {
		return {
			queryKey: [&quot;user&quot;, user.id],
			queryFn: () =&gt; fetchUserById(user.id),
		};
	}),
});

console.log(results);
/*
[
  { data: user, isLoading: false, isError: false, ... },  // 第一个查询
  { data: posts, isLoading: true, isError: false, ... },   // 第二个查询
  { data: null, isLoading: false, isError: true, ... },    // 第三个查询
]
*/
useIsFetching | 检查是否有查询正在进行
import { useIsFetching } from &quot;@tanstack/react-query&quot;;

function GlobalLoadingIndicator() {
	const isFetching = useIsFetching();

	return isFetching ? (
		&lt;div&gt;Queries are fetching in the background...&lt;/div&gt;
	) : null;
}
useMutation Hook
处理数据修改操作的 Hook，用于 POST、PUT、DELETE 等会改变服务器状态的操作。典型的例子：提交表单、删除用户、更新设置
基本用法
const mutation = useMutation({
	// 1. 核心函数：执行修改操作
	mutationFn: async (newData) =&gt; {
		const response = await api.createData(newData);
		return response.data;
	},

	// 2. 可选：乐观更新配置
	onMutate: async (variables) =&gt; {
		// 在请求发送前执行
		// 用途：提前更新UI，待请求成功后再更新数据，场景：提交评论时，先显示评论内容，接口成功再更新数据，接口失败则回滚
	},

	// 3. 可选：成功/失败回调
	// 如果组件在回调完成之前卸载，则不会触发
	// data: 接口返回的数据
	// variables: 传递给mutationFn的参数
	// onMutateResult: onMutate的返回值
	// context: 上下文对象
	onSuccess: (data, variables, onMutateResult, context) =&gt; {
		// 请求成功时执行
	},

	onError: (error, variables, onMutateResult, context) =&gt; {
		// 请求失败时执行
	},

	onSettled: (data, error, variables, onMutateResult, context) =&gt; {
		// 无论成功失败都会执行
		// onSuccess/onError 完成后才执行，相当于onfinish
	},

	// 4. 重试配置
	retry: 3, // 失败时重试次数
	retryDelay: 1000, // 重试延迟
});
const { mutate, isPending, isSuccess, isError, error } = useCreateArticle();
mutate(
	{ title, content },
	{
		onSuccess: () =&gt; {
			// ...
		},
	},
);
// 1. 创建 QueryClient 实例 - React Query 的核心管理器
const queryClient = new QueryClient();

// 2. 为 &quot;addTodo&quot; 变更设置全局默认配置
// 这会在应用级别为所有使用 [&#039;addTodo&#039;] 作为 mutationKey 的变更提供默认行为
queryClient.setMutationDefaults([&quot;addTodo&quot;], {
	// mutationFn: 实际执行数据变更的异步函数
	mutationFn: addTodo,

	// onMutate: 在变更执行前立即调用，用于乐观更新
	// 乐观更新：假设变更会成功，先更新UI，如果失败再回滚
	onMutate: async (variables, context) =&gt; {
		// 取消当前正在进行的 todos 查询，避免数据冲突
		await context.client.cancelQueries({ queryKey: [&quot;todos&quot;] });

		// 创建一个临时的乐观待办事项对象
		// uuid() 生成唯一ID，确保临时对象不与其他数据冲突
		const optimisticTodo = { id: uuid(), title: variables.title };

		// 将乐观待办事项添加到 todos 列表中
		// setQueryData 直接更新缓存，UI会立即响应
		context.client.setQueryData([&quot;todos&quot;], (old) =&gt; [
			...old,
			optimisticTodo,
		]);

		// 返回乐观更新的上下文信息
		// 这个返回值会传递给 onSuccess 和 onError 的 onMutateResult 参数
		return { optimisticTodo };
	},

	// onSuccess: 变更成功完成时调用
	onSuccess: (result, variables, onMutateResult, context) =&gt; {
		// 用服务器返回的实际数据替换临时的乐观待办事项
		// onMutateResult.optimisticTodo.id 是之前在 onMutate 中生成的临时ID
		context.client.setQueryData([&quot;todos&quot;], (old) =&gt;
			old.map((todo) =&gt;
				// 找到临时待办事项，用服务器返回的真实数据替换它
				todo.id === onMutateResult.optimisticTodo.id ? result : todo,
			),
		);
	},

	// onError: 变更失败时调用
	onError: (error, variables, onMutateResult, context) =&gt; {
		// 从 todos 列表中移除乐观待办事项（回滚操作）
		// 过滤掉之前添加的临时待办事项
		context.client.setQueryData([&quot;todos&quot;], (old) =&gt;
			old.filter((todo) =&gt; todo.id !== onMutateResult.optimisticTodo.id),
		);
	},

	// retry: 失败时自动重试次数
	retry: 3,
});

// 3. 在组件中使用变更
// 注意：这里只需要指定 mutationKey，其他配置会自动继承 setMutationDefaults 中的设置
const mutation = useMutation({ mutationKey: [&quot;addTodo&quot;] });

// 4. 触发变更执行
// mutate 方法会调用 addTodo 函数，并传递 { title: &#039;title&#039; } 作为参数
mutation.mutate({ title: &quot;title&quot; });

// 5. 离线恢复机制 - 脱水（序列化）
// 如果变更因为设备离线而被暂停，可以在应用退出时序列化状态
// 这通常用于 PWA 或移动应用的离线功能
const state = dehydrate(queryClient);
// state 现在包含了所有查询和变更的当前状态，可以存储到本地存储

// 6. 离线恢复机制 - 水合（反序列化）
// 当应用重新启动时，从存储中恢复状态
hydrate(queryClient, state);
// 这会恢复之前所有的查询和变更状态

// 7. 恢复被暂停的变更
// 当应用重新上线时，恢复之前因离线而暂停的变更
queryClient.resumePausedMutations();
// 这会导致之前暂停的变更继续执行
prefetchQuery Hook | prefetchInfiniteQuery Hook
预取数据 ，旨在通过提前加载数据来优化用户体验
基本使用
// 普通查询
await queryClient.prefetchQuery({
	queryKey: [&quot;todos&quot;],
	queryFn: fetchTodos,
	staleTime: 5000, // 仅为预取设置
});

// 无限查询 (预取前 3 页)
await queryClient.prefetchInfiniteQuery({
	queryKey: [&quot;projects&quot;],
	queryFn: fetchProjects,
	initialPageParam: 0,
	getNextPageParam: (lastPage) =&gt; lastPage.nextCursor,
	pages: 3, // 预取页数
});
使用场景
A. 事件驱动预取 (Event Handlers)
在用户交互（如悬停、聚焦）时触发，适合预测用户下一步操作。

最佳实践：必须设置 staleTime，避免频繁重复请求。
示例：按钮 onMouseEnter时预取详情数据。

B. 组件内预取 (Components)
用于解决“请求瀑布”问题（如父组件加载完才触发子组件加载）。
C. 依赖预取与代码分割 (Dependent Queries)
解决“先加载组件代码，再加载数据”的串行问题。

策略：在父级查询函数 (queryFn) 中，根据返回结果动态预取子组件数据。
效果：实现组件代码加载与数据加载的并行化。
权衡 (Trade-off)：预取逻辑会提升父级 Bundle 体积，需根据“命中率”决定是否值得。

// 假设我们有一个 Feed页面，其条目可能包含标准项和一种特殊的、包含复杂图表的项。由于图表组件（GraphFeedItem）及其数据获取逻辑较重，我们对其使用了 React.lazy进行代码分割，实现按需加载。
// 先加载 Feed 数据，同时预取图表数据，避免“请求瀑布”问题。
// Feed.tsx
// 1. 图表组件被懒加载
const GraphFeedItem = React.lazy(() =&gt; import(&quot;./GraphFeedItem&quot;));

function Feed() {
	const { data, isPending } = useQuery({
		queryKey: [&quot;feed&quot;],
		queryFn: async (...args) =&gt; {
			// 1. 先获取 Feed 列表
			const feed = await getFeed(...args);

			// 2. 关键步骤：遍历列表，对图表项进行条件预取
			for (const feedItem of feed) {
				if (feedItem.type === &quot;GRAPH&quot;) {
					// 立即（不 await）发起图表数据的预取请求
					queryClient.prefetchQuery({
						queryKey: [&quot;graph&quot;, feedItem.id],
						queryFn: getGraphDataById, // 注意：这里导入了获取函数
					});
				}
			}
			// 3. 返回 Feed 数据
			return feed;
		},
	});

	if (isPending) return &quot;Loading feed...&quot;;

	return (
		&lt;&gt;
			{data.map((feedItem) =&gt; {
				// 3. 只有遇到类型为 &#039;GRAPH&#039; 的项时，才会开始加载 GraphFeedItem 的 JS 代码包
				if (feedItem.type === &quot;GRAPH&quot;) {
					return (
						&lt;GraphFeedItem key={feedItem.id} feedItem={feedItem} /&gt;
					);
				}
				return (
					&lt;StandardFeedItem key={feedItem.id} feedItem={feedItem} /&gt;
				);
			})}
		&lt;/&gt;
	);
}
// GraphFeedItem.tsx
// 4. 组件代码加载完成后，渲染时才触发其内部的数据查询
function GraphFeedItem({ feedItem }) {
	const { data, isPending } = useQuery({
		queryKey: [&quot;graph&quot;, feedItem.id],
		queryFn: getGraphDataById,
	});
	// ... 渲染图表
}
配置项（Query Options）
基本配置


queryKey：查询键


queryFn：查询函数


enabled：是否启用查询


staleTime：数据过时时间


gcTime：缓存时间 这个机制在查询仍被使用的情况下不会起任何作用。只有当查询不再被使用时，该机制才会开始发挥作用。时间一到，相关数据就会被“清除”，从而防止缓存规模不断增大


retry：重试次数 (Number | Boolean)


retryDelay：重试延迟时间


refetchOnWindowFocus: 窗口聚焦时重新获取数据 default: true


placeholderData : 占位数据 分页查询时很有用 placeholderData: keepPreviousData
import { keepPreviousData, useQuery } from &quot;@tanstack/react-query&quot;;
useQuery({
	queryKey: [&quot;projects&quot;, page],
	queryFn: () =&gt; fetchProjects(page),
	// 在请求新数据的过程中，上一次成功获取的数据仍然存在，即便查询键已经发生了变化。当新数据到达时，之前的数据就会被替换
	placeholderData: keepPreviousData,
});


查询无效化 与 过滤器
一、过滤器（Filters）核心概念
过滤器是用于批量匹配查询（Query）或变更（Mutation）的条件对象，作为筛选器传递给缓存操作方法。
QueryFilters 主要属性：

queryKey - 查询键（支持前缀匹配）
exact - 精确匹配（默认 false）
type - 匹配类型：&#039;active&#039; | &#039;inactive&#039; | &#039;all&#039;
predicate - 自定义过滤函数

MutationFilters 主要属性：

mutationKey - 变更键
exact - 精确匹配
fetching - 匹配进行中的变更
predicate - 自定义过滤函数

二、查询无效化三方法对比

































方法核心作用数据保留网络请求适用场景invalidateQueries标记为过时，触发后台重新获取✅ 保留（标记 stale）✅ 触发重新获取数据更新后同步、定时刷新removeQueries从缓存彻底删除❌ 完全删除❌ 不触发清理敏感数据、释放内存、重置状态cancelQueries中止进行中的网络请求✅ 保留现有数据❌ 中止当前请求防止竞态、优化性能、搜索防抖
三、核心区别总结

invalidateQueries：最常用，实现无缝数据更新，UI 无闪烁
removeQueries：最彻底，立即释放内存，但会导致 UI 显示 Loading
cancelQueries：最特殊，仅中止请求，不改变缓存状态

nodsjs.content:
fs 模块
引入
const fs = require(&quot;fs&quot;);
// fs 模块提供了 promises 版本的 API
const fs = require(&quot;fs&quot;).promises;
fs.readFile
fs.readFile 以异步的方式读取整个文件内容，在读取完成后通过回调函数返回结果。这意味着在文件读取过程中，Node.js 可以继续执行其他代码，不会阻塞事件循环。
fs.readFile(path[, options], callback)
参数说明


path：表示要读取的文件的路径，可以是字符串、Buffer 或 URL 对象。


options
（可选）：一个对象或字符串，用于指定读取文件的选项，常用属性如下：

encoding：指定文件内容的编码格式，例如 &#039;utf8&#039; 表示以 UTF-8 编码读取文件。如果不指定该属性，读取的结果将是一个 Buffer 对象。
flag：指定文件的打开标志，默认值是 &#039;r&#039;，表示以只读模式打开文件。



callback
：读取完成后的回调函数，它接收两个参数：

err：如果读取过程中发生错误，该参数将包含错误对象；如果没有错误，该参数为 null。
data：读取到的文件内容，如果指定了 encoding 选项，data 是一个字符串；否则，data 是一个 Buffer 对象。



fs.writeFile
fs.writeFile 以异步的方式将数据写入文件。如果文件不存在，它会创建该文件；如果文件已存在，默认情况下会覆盖原有内容。在写入完成后，通过回调函数返回结果。这种异步操作方式不会阻塞 Node.js 的事件循环，在文件写入过程中可以继续执行其他代码
fs.writeFile(file, data[, options], callback)

参数说明


file：表示要写入的文件的路径，可以是字符串、Buffer 或 URL 对象。


data：要写入文件的数据，可以是字符串、Buffer、TypedArray 或 DataView。


options
（可选）：一个对象或字符串，用于指定写入文件的选项，常用属性如下：

encoding：指定写入数据的编码格式，默认值是 &#039;utf8&#039;。
mode：指定文件的权限，默认值是 0o666。
flag：指定文件的打开标志，默认值是 &#039;w&#039;，表示以写入模式打开文件，如果文件存在则覆盖，不存在则创建。其他常用标志还有 &#039;a&#039; 表示追加写入。



callback
：写入完成后的回调函数，它接收一个参数：

err：如果写入过程中发生错误，该参数将包含错误对象；如果没有错误，该参数为 null。



__dirname
__dirname 是一个全局变量，它代表当前执行脚本所在的目录的绝对路径
path 模块
引入
const path = require(&quot;path&quot;);
path.join([…paths])
用于将多个路径片段拼接成一个规范化的路径。它会处理路径分隔符，确保在不同操作系统上都能正常工作
const filePath = path.join(&quot;home&quot;, &quot;user&quot;, &quot;documents&quot;, &quot;file.txt&quot;);
console.log(filePath);
// 在 POSIX 系统上输出: home/user/documents/file.txt
// 在 Windows 系统上输出: home\user\documents\file.txt
path.resolve([…paths])
将路径或路径片段解析为绝对路径。它从右到左处理路径片段，直到构建出一个绝对路径。如果没有提供绝对路径片段，它会使用当前工作目录
const absolutePath = path.resolve(&quot;home&quot;, &quot;user&quot;, &quot;documents&quot;, &quot;file.txt&quot;);
console.log(absolutePath); // 输出当前工作目录下的绝对路径，例如: /Users/currentuser/home/user/documents/file.txt
path.basename(path[, ext])
返回路径的最后一部分，即文件名。可以通过第二个参数指定文件扩展名，若指定则会将其从返回值中去除。
const fullPath = &quot;/home/user/documents/file.txt&quot;;
const fileName = path.basename(fullPath);
console.log(fileName); // 输出: file.txt

const withoutExt = path.basename(fullPath, &quot;.txt&quot;);
console.log(withoutExt); // 输出: file
path.dirname(path)
返回路径的目录名，即路径中除最后一部分（文件名）之外的部分。
const fullPath = &quot;/home/user/documents/file.txt&quot;;
const dirName = path.dirname(fullPath);
console.log(dirName); // 输出: /home/user/documents
path.extname(path)
返回路径的文件扩展名，包括点号（.）。如果路径中没有扩展名，则返回空字符串。
const fullPath = &quot;/home/user/documents/file.txt&quot;;
const ext = path.extname(fullPath);
console.log(ext); // 输出: .txt

const noExtPath = &quot;/home/user/documents&quot;;
const noExt = path.extname(noExtPath);
console.log(noExt); // 输出: &#039;&#039;
path.normalize(path)
规范化给定的路径，解析 . 和 .. 等相对路径部分，并处理多余的分隔符。
const pathToNormalize = &quot;/home/user/../documents/./file.txt&quot;;
const normalizedPath = path.normalize(pathToNormalize);
console.log(normalizedPath);
// 在 POSIX 系统上输出: /home/documents/file.txt
// 在 Windows 系统上输出: \home\documents\file.txt
HTTP 模块
引入
const http = require(&quot;http&quot;);
创建一个 http 服务器实例
const http = require(&quot;http&quot;);
// 创建一个 HTTP 服务器实例
const server = http.createServer((req, res) =&gt; {
	//...
});
// 让服务器监听 3000 端口
server.listen(3000, () =&gt; {
	console.log(&quot;Server is running on port 3000&quot;);
});

http.createServer 方法用于创建一个 HTTP 服务器实例，它接受一个回调函数作为参数，该回调函数会在每次接收到请求时被调用。
req 参数是一个 http.IncomingMessage 对象，它包含了客户端请求的信息，如请求方法、请求头、请求 URL 等。
res 参数是一个 http.ServerResponse 对象，用于向客户端发送响应。

server.on(&quot;request&quot;, (req, res) =&gt; {
	let body = &quot;&quot;;
	/**
	 * req.method 获取请求的方法
	 * req.url 获取请求的URL地址
	 * req.headers 获取请求头
	 * req.setTimeout(timeout[, callback]) 设置请求的超时时间
	 */
	// 获取请求体数据
	req.on(&quot;data&quot;, (chunk) =&gt; {
		// chunk 是请求体的数据片段
		body += chunk;
	});
	// 当请求体数据全部接收完毕时触发
	req.on(&quot;end&quot;, () =&gt; {
		console.log(&quot;完整的请求体数据:&quot;, body);
	});
	/**
	 * res.statusCode 设置响应状态码
	 * res.statusMessage 设置响应状态信息
	 * res.setHeader(name, value) 设置响应头
	 * res.getHeader(name) 获取响应头
	 * res.writeHead(statusCode[, statusMessage][, headers]) 设置响应头和状态码
	 * res.write(chunk[, encoding][, callback]) 写入响应体数据
	 * res.end([data[, encoding]][, callback]) 结束响应
	 * res.destroy([error]) 销毁响应
	 * res.on(&#039;finish&#039;) 当响应结束时触发
	 */
});
