tslearning.content:
ts数据类型

原始类型：number/string/boolean/null/undefined/symbol
对象类型：object（包括，数组、对象、函数等对象）
ts 新增类型：联合类型 / 自定义类型(类型别名) / 接口 / 元组 / 字面量类型 / 枚举 / void / any / 等等

原始类型
// 数值类型
let age: number = 18

// 字符串类型
let myName: string = &#039;小花&#039;

// 布尔类型
let isLoading: boolean = false

// undefined
let un: undefined = undefined

// null
let timer:null = null

// symbol
let uniKey:symbol = Symbol() 
对象类型
函数
// function
// (普通函数)
function add(num1:number,num2:number):number {
    return num1 + num2
}
// （箭头函数）
const add2 = (num1:number,num2:number):number =&gt; {
    return num1 + num2
}
// （函数返回值是underfunded 或 无返回值）
function alert(msg:string):void{
    console.log(msg);
}
// （函数可选参数）
function slice(a?:number,b?:number):void{
    console.log(111);
}
// （函数默认参数）
function getName(firstName:string = &#039;mike&#039;,lastName?:string):string{
    return firstName + lastName
}
对象
// Object
let obj1 : {
    a:number,
    b:string,
    c?:Boolean
} = {
    a:1,
    b:&#039;2&#039;
}
数组
// Array
let list:number[] = [1,2,3]
let attr:Array&lt;String&gt; = [&#039;1&#039;,&#039;2&#039;,&#039;3&#039;]

联合类型
let 变量: 类型1 | 类型2 | 类型3 .... = 初始值
let arr1 :number | string = 1 // 可以写两个类型 
let timer:number|null = null
类型别名
type 别名 = 类型
type s = string // 定义
----------------------------
const str1:s = &#039;abc&#039;
const str2:string = &#039;abc&#039; 

// 统一定义一个函数类型
type Fn = (n1:number,n2:number) =&gt; number 
const add3 : Fn = (a,b)=&gt;{return a+b }

// 对象别名
type Person = {
    name:string,
    age:number,
    sayHi():void
}
let person:Person = {
    name:&#039;li&#039;,
    age:88,
    sayHi(){
        console.log(&#039;hello&#039;);
    }
}
接口
当一个对象类型被多次使用时，有如下两种方式来来描述对象的类型，以达到复用的目的：

类型别名，type
接口，interface

区别

相同点：都可以给对象指定类型
不同点:

接口，只能为对象指定类型。它可以继承。
类型别名，不仅可以为对象指定类型，实际上可以为任意类型指定别名



属性接口
interface Person {
  name: string;
  age: number;
}
function greet(person: Person) {
  console.log(`Hello, my name is ${person.name} and I&#039;m ${person.age} years old.`);
}
let john: Person = {
  name: &quot;John&quot;,
  age: 18
};
greet(john); // 输出：Hello, my name is John and I&#039;m 18 years old.
可选属性 与 只读属性 与 必选属性
interface Person {
     readonly name: string;
     age?: number;
}
function greet(person: Person) {
     console.log(`my name is ${person.name}, my age is ${person.age}`);
}
let john: Person = {
     name: &quot;John&quot;,
     age: 30,
};
john.name = &quot;peter&quot;; // 错误!
greet(john); // 输出：my name is John, my age is 30

// 必选
type IAnimal = {
    name?: string
    age?: number
    hobby?: string[]
}
type IDog = {
    [key in keyof IAnimal]-?: string
}
函数接口
函数接口是一种描述函数类型的接口，用来规范函数的参数类型和返回值类型等信息。
interface SayHi {
    (word:string):string
}
let sayHi:SayHi = function(word:string):string {
    return &#039;hello,&#039;+word
}
console.log(sayHi(&#039;Mike&#039;));// hello,Mike
可索引接口
可索引接口是一种描述数组和对象的接口，用来规范它们的索引类型和索引值类型等信息。
// 索引为数字的数组或对象
interface StringArray {
    [index: number]: string;
}
let colors: StringArray = [&quot;Red&quot;, &quot;Green&quot;, &quot;Blue&quot;];
let colors_2: StringArray = {0:&#039;Red&#039;,1:&#039;Green&#039;,2:&#039;Blue&#039;}
console.log(colors[0]); // 输出：Red

// 索引为字符串的对象
interface StringObject {
    [index: string]: string;
}
let words: StringObject = {
    &#039;hello&#039;:&#039;hello&#039;
}
console.log(words[&#039;hello&#039;]); // 输出：hello
类接口
类接口是一种描述类类型的接口，用来规范类的成员和属性等信息。
interface Person {
  name: string;
  age: number;
  greet(name: string): void;
}

// implements关键字用于指定一个类或类接口应该实现另一个接口。
// 这里，我们使用implements关键字来指定Clock类应该实现ClockInterface接口
class Student implements Person {
  constructor(public name: string, public age: number) {}

  greet(name: string) {
    console.log(`Hello, ${name}, I&#039;m ${this.name}.`);
  }
}

let john: Person = new Student(&quot;John&quot;, 18);
john.greet(&quot;Jane&quot;); // 输出：Hello, Jane, I&#039;m John.
混合接口
混合接口是一种同时描述函数、类和对象等多种类型的接口，用来规范它们的成员和属性等信息
interface Counter {
    (start: number): string;
    interval: number;
    reset(): void;
}

function createCounter(): Counter {
    let counter = function(start: number) {} as Counter;
    // 或者 let counter = &lt;Counter&gt;function (start: number) { };
    counter.interval = 10;
    counter.reset = function() {};
    return counter;
}

let c = createCounter();
c(10);
c.reset();
c.interval = 5.0      
接口继承
如果两个接口之间有相同的属性或方法，可以将公共的属性或方法抽离出来，通过继承来实现复用 语法
interface IGoodItems2 extends IGoodItems{
  	price:number
}
元组

元组是一种特殊的数组。有两点特殊之处


它约定了的元素个数
它约定了特定索引对应的数据类型

// 例1
function useState(n: number): [number, (number)=&gt;void] {
        const setN = (n1) =&gt; {
            n = n1
        }
        return [n, setN]
    }

const [num ,setNum] = useState(10) 

// 例2
var x: [string, number];
// 初始化他
x = [&#039;hello&#039;, 10]; // 准确
字面量类型
字面量类型一般是配合联合类型一起使用的， 用来表示一组明确的可选值列表。
// str1 是一个变量(let)，它的值可以是任意字符串，所以类型为:string
let str1 = &#039;hello TS&#039;
// str2 是一个常量(const)，它的值不能变化只能是 ‘hello TS’，所以，它的类型为:‘hello TS’
const str2 = &#039;hello TS&#039; 
type Gender = &#039;girl&#039; | &#039;boy&#039;
// 声明一个类型，他的值 是 &#039;girl&#039; 或者是 &#039;boy&#039;
let g1: Gender = &#039;girl&#039; // 正确
let g2: Gender = &#039;boy&#039; // 正确
let g3: Gender = &#039;man&#039; // 错误 
枚举
枚举（enum）的功能类似于字面量类型+联合类型组合的功能，来描述一个值，该值只能是 一组命名常量 中的一个。

一般枚举名称以大写字母开头
枚举中的多个值之间通过 ,（逗号）分隔
定义好枚举后，直接使用枚举名称作为类型注解

enum 枚举名 { 可取值1, 可取值2,.. }

// 使用格式：
枚举名.可取值 
枚举分为 数值枚举 和 字符串枚举。


数值枚举: 拥有自增长行为，默认为从 0 开始自增的数值；当然，也可以给枚举中的成员初始化值
enum Direction { Up = 10, Down, Left, Right }
// console.log(Direction.Down)   =&gt; 11
// console.log(Direction.Left)   =&gt; 12
// console.log(Direction.Right)  =&gt; 13

enum Direction { Up = 2, Down = 3, Left = 8, Right = 16 } 


字符串枚举:  字符串枚举没有自增长行为，因此，字符串枚举的每个成员必须有初始值
enum Direction {
  Up = &#039;UP&#039;,
  Down = &#039;DOWN&#039;,
  Left = &#039;LEFT&#039;,
  Right = &#039;RIGHT&#039;
} 


any 类型
泛型
泛型指的是在定义函数/接口/类型时，不预先指定具体的类型，而是在使用的时候在指定类型限制的一种特性
泛型用法
1.在接口中使用泛型
// 注意，这里写法是定义的方法哦
interface Search {
  &lt;T,Y&gt;(name:T,age:Y):T
}

let fn:Search = function &lt;T, Y&gt;(name: T, id:Y):T {
  console.log(name, id)
  return name;
}
fn&lt;string,number&gt;(&#039;li&#039;,11);//编译器会自动识别传入的参数，将传入的参数的类型认为是泛型指定的类型
2.在类中使用泛型
class Animal&lt;T&gt; {
 name:T;
 constructor(name: T){
  this.name = name;
 }
 action&lt;T&gt;(say:T) {
   console.log(say)
 }
}
let cat = new Animal(&#039;cat&#039;);
cat.action(&#039;mimi&#039;)
3.在函数中使用泛型
function test &lt;T&gt; (arg:T):T{
  console.log(arg);
  return arg;
}
test&lt;number&gt;(111);// 返回值是number类型的 111
test&lt;string | boolean&gt;(&#039;hahaha&#039;)//返回值是string类型的 hahaha
test&lt;string | boolean&gt;(true);//返回值是布尔类型的 true
泛型约束
为泛型添加约束来收缩类型(缩窄类型取值范围)
1 指定更加具体的类型
function id&lt;Type&gt;(value: Type[]): Type[] {
  console.log(value.length)
  return value
}
2 添加约束
// 例子1
interface Ilength {
    length:number
}
function idss&lt;T extends Ilength&gt;(arr:T):T {
    console.log(arr.length);
    return arr        
}
idss({ length:10, value:&#039;00&#039; })
